// Normalize Gmail results to standard thread shape
const threads = $input.all().filter(i => i.json.threadId).map(i => ({
  thread_id: i.json.threadId,
  subject: i.json.snippet ? i.json.snippet.slice(0, 200) : '',
  date: i.json.internalDate ? new Date(parseInt(i.json.internalDate)).toISOString() : ''
}));

return {
  email_threads: threads,
  thread_count: threads.length
};
